/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// Convolution Functions

int32_t riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any(const int8_t * in_tensor,
                                                          const uint16_t in_tensor_dim_x,
                                                          const uint16_t in_tensor_dim_y,
                                                          const uint16_t in_tensor_ch,
                                                          const uint16_t in_tensor_batch,
                                                          const int8_t * ker_weight,
                                                          const uint16_t out_tensor_ch,
                                                          const uint16_t pad_x,
                                                          const uint16_t pad_y,
                                                          const uint16_t stride_x,
                                                          const uint16_t stride_y,
                                                          const int32_t * bias,
                                                          int8_t * out_tensor,
                                                          const int32_t * out_shift,
                                                          const int32_t * out_scale,
                                                          const int32_t out_offset,   //value is in the range of [-128, 127]
                                                          const int32_t in_offset,    //value is in the range of [-127, 128]
                                                          const int32_t act_min,
                                                          const int32_t act_max,
                                                          const uint16_t out_tensor_dim_x,
                                                          const uint16_t out_tensor_dim_y,
                                                          int16_t * tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING) && !defined(ENA_VEC_ELEN64)
    if ((pad_x != 0) ||
        (pad_y != 0))
    {
        return -1;
    }

    /////////////////////////////////////////////////// START CALC CONTRI///////////////////////////////////////
    // calculate the weight contribution
    int32_t contri_buf[out_tensor_ch];
    const int8_t *pWt = ker_weight;
    long vl;
    long maxvl_per_vg;
    NDS_VEC_VSETVLI(maxvl_per_vg, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

    if (bias != NULL)
    {
        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
        {
            long in_tensor_ch2 = in_tensor_ch;
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);     // init the acculators
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);                // const one for vd4dot

            while (in_tensor_ch2 >= maxvl_per_vg)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            //clean one of the dot product source
            long tmp_vl = in_tensor_ch2 + 3;
            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);

            while (in_tensor_ch2 > 0)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            const int32_t *pBias = &bias[cur_out_ch];
            NDS_VEC_VLE32_V(NDS_VEC_V8, pBias);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution back
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);    // add bias

            int32_t *pContri_buf = &contri_buf[cur_out_ch];
            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
        }
    }
    else
    {
        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
        {
            long in_tensor_ch2 = in_tensor_ch;
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
