        const int32_t rhs_cols = in_tensor_ch;
        const int32_t lhs_cols_offset = rhs_cols;

        nn_mat_mult_nt_t_s8(in_tensor,
                            ker_weight,
                            bias,
                            out_tensor,
                            out_scale,
                            out_shift,
                            lhs_rows,
                            rhs_rows,
                            rhs_cols,
                            in_offset,
                            out_offset,
                            act_min,
                            act_max,
                            lhs_cols_offset);
    }
    else
    {
        const int32_t lhs_rows = out_tensor_dim_x;
        const int32_t rhs_rows = out_tensor_ch;
        const int32_t rhs_cols = in_tensor_ch;
        const int32_t input_inc = in_tensor_dim_x * stride_y * rhs_cols;
        const int32_t output_inc = out_tensor_dim_x * rhs_rows;
        const int32_t lhs_cols_offset = rhs_cols * stride_x;

        for (int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
        {
            const int8_t *in_tensor2 = in_tensor + (i_batch * in_tensor_dim_y * in_tensor_dim_x * in_tensor_ch);
            for (int i_output_y = 0; i_output_y < out_tensor_dim_y; i_output_y++)
            {
                // Process one input row
                nn_mat_mult_nt_t_s8(in_tensor2,
                                    ker_weight,
                                    bias,
                                    out_tensor,
                                    out_scale,
                                    out_shift,
                                    lhs_rows,
                                    rhs_rows,
                                    rhs_cols,
                                    in_offset,
                                    out_offset,
                                    act_min,
                                    act_max,
                                    lhs_cols_offset);
                in_tensor2 += input_inc;
                out_tensor += output_inc;
            }
        }
    }
#endif  //ENA_EMPTY_FUN

    /* Return to application */
    return 0;
}

int32_t riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any_get_buffer_size(const uint16_t in_tensor_dim_x,
                                                                          const uint16_t in_tensor_dim_y,
                                                                          const uint16_t in_tensor_ch,
                                                                          const uint16_t out_tensor_ch,
                                                                          const uint16_t pad_x,
                                                                          const uint16_t pad_y,
                                                                          const uint16_t stride_x,
                                                                          const uint16_t stride_y,
                                                                          const uint16_t out_tensor_dim_x,
                                                                          const uint16_t out_tensor_dim_y)
{
    (void) pad_x;
    (void) pad_y;
    (void) stride_x;
    (void) stride_y;
    (void) out_tensor_dim_x;
    (void) out_tensor_dim_y;
    int32_t buf_size = 0;
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING) && !defined(ENA_VEC_ELEN64)
    uint32_t buf_A = 0, buf_B = 0, buf_C = 0;
    const long align_byte = 64;
    uint32_t tiling_size = 256;
#ifdef DCACHE_SIZE
    int i;
    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / (6 * sizeof(int8_t)));
    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
    {
        if (tiling_size_arr[i] > max_tile_size_in_cache)
        {
            tiling_size = tiling_size_arr[i - 1];
            break;
        }
    }
#endif
    if ((stride_x == 1) && (stride_y == 1))
    {
        buf_C = in_tensor_dim_x * in_tensor_dim_y * out_tensor_ch * sizeof(int32_t); //temp buffer for q31 tiling accumulator
        buf_C += align_byte - 1;
    }
    else
    {
        buf_A = tiling_size * in_tensor_ch * sizeof(int8_t); //tiling version
        buf_A += align_byte - 1;
        buf_C = tiling_size * out_tensor_ch * sizeof(int32_t); //temp buffer for q31 tiling accumulator
        buf_C += align_byte - 1;
    }
    buf_B = out_tensor_ch * in_tensor_ch * sizeof(int8_t); //converted src2
    buf_B += align_byte - 1;
    buf_size = buf_A + buf_B + buf_C;
#else
    (void) in_tensor_dim_x;
    (void) in_tensor_dim_y;
    (void) in_tensor_ch;
    (void) out_tensor_ch;
#endif
    return buf_size;
}

