/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// Convolution Functions

int32_t riscv_nn_conv_1x1_HWC_s8_s8_s8_asym_bias_fast_any(const int8_t * in_tensor,
                                                          const uint16_t in_tensor_dim_x,
                                                          const uint16_t in_tensor_dim_y,
                                                          const uint16_t in_tensor_ch,
                                                          const uint16_t in_tensor_batch,
                                                          const int8_t * ker_weight,
                                                          const uint16_t out_tensor_ch,
                                                          const uint16_t pad_x,
                                                          const uint16_t pad_y,
                                                          const uint16_t stride_x,
                                                          const uint16_t stride_y,
                                                          const int32_t * bias,
                                                          int8_t * out_tensor,
                                                          const int32_t * out_shift,
                                                          const int32_t * out_scale,
                                                          const int32_t out_offset,   //value is in the range of [-128, 127]
                                                          const int32_t in_offset,    //value is in the range of [-127, 128]
                                                          const int32_t act_min,
                                                          const int32_t act_max,
                                                          const uint16_t out_tensor_dim_x,
                                                          const uint16_t out_tensor_dim_y,
                                                          int16_t * tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING) && !defined(ENA_VEC_ELEN64)
    if ((pad_x != 0) ||
        (pad_y != 0))
    {
        return -1;
    }

    /////////////////////////////////////////////////// START CALC CONTRI///////////////////////////////////////
    // calculate the weight contribution
    int32_t contri_buf[out_tensor_ch];
    const int8_t *pWt = ker_weight;
    long vl;
    long maxvl_per_vg;
    NDS_VEC_VSETVLI(maxvl_per_vg, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

    if (bias != NULL)
    {
        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
        {
            long in_tensor_ch2 = in_tensor_ch;
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);     // init the acculators
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);                // const one for vd4dot

            while (in_tensor_ch2 >= maxvl_per_vg)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            //clean one of the dot product source
            long tmp_vl = in_tensor_ch2 + 3;
            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);

            while (in_tensor_ch2 > 0)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            const int32_t *pBias = &bias[cur_out_ch];
            NDS_VEC_VLE32_V(NDS_VEC_V8, pBias);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution back
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);    // add bias

            int32_t *pContri_buf = &contri_buf[cur_out_ch];
            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
        }
    }
    else
    {
        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
        {
            long in_tensor_ch2 = in_tensor_ch;
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);    // const one for vd4dot

            while (in_tensor_ch2 >= maxvl_per_vg)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            //clean one of the dot product source
            long tmp_vl = in_tensor_ch2 + 3;
            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);

            while (in_tensor_ch2 > 0)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

            // add input_offset contribution back
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);

            int32_t *pContri_buf = &contri_buf[cur_out_ch];
            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
        }
    }
    /////////////////////////////////////////////////// END CALC CONTRI///////////////////////////////////////

    //cache is 512KB, type is q7
    uint32_t tiling_size = 256;
    const long align_byte = 64;
    unsigned long addr_in_tmp_buf;
    int8_t *pOut = out_tensor;
    int8_t *src1 = (int8_t *) in_tensor;
    int8_t *src2;
    int32_t *dst_i32;

    if ((stride_x == 1) && (stride_y == 1))
    {
        src2 = (int8_t *)tmp_buf;
    }
    else
    {
        src2 = (int8_t *)tmp_buf + sizeof(*in_tensor) * tiling_size * in_tensor_ch; //matrix_A's memory space
        src2 = (int8_t *)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
    }

    addr_in_tmp_buf = (unsigned long)src2 + sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
    dst_i32 = (int32_t *)addr_in_tmp_buf;

    //transpose the kernel_weight for matrix multiplication
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, out_tensor_ch, in_tensor_ch);

    if ((stride_x == 1) && (stride_y == 1))
    {
        for(int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
        {
            pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
                                                          src2,
                                                          dst_i32,
                                                          pOut,
                                                          out_scale,
                                                          out_shift,
                                                          in_tensor_dim_x * in_tensor_dim_y,
                                                          in_tensor_ch,
                                                          out_tensor_ch,
                                                          out_offset,
                                                          act_min,
                                                          act_max,
                                                          contri_buf,
                                                          tiling_size);
            /* next in_tensor batch offset */
            src1 += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        }
    }
    else
    {
        for(int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
        {
            int8_t *pBuffer = (int8_t *)tmp_buf;
            int col_counter = 0;
            int16_t i_out_y, i_out_x;

            /* This part implements the im2col function */
            for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
            {
                for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
                {
                    /* Copying the pixel data to column */
                    nn_dup_s8((int8_t *)in_tensor + (i_out_y * stride_y * in_tensor_dim_x + i_out_x * stride_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    pBuffer += in_tensor_ch;
                    col_counter++;

                    /* Computation is filed for [tiling_size] columns */
                    if (col_counter == tiling_size)
                    {
                        pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8((int8_t *)tmp_buf,
                                                                      src2,
                                                                      dst_i32,
                                                                      pOut,
                                                                      out_scale,
                                                                      out_shift,
                                                                      col_counter,
                                                                      in_tensor_ch,
                                                                      out_tensor_ch,
                                                                      out_offset,
                                                                      act_min,
                                                                      act_max,
                                                                      contri_buf,
                                                                      tiling_size);
                        /* reset */
                        col_counter = 0;
                        pBuffer = (int8_t *)tmp_buf;
                    }
                }
            }

            /* check if there is left-over for compute */
            pOut = nn_mat_mul_kernel_tiling_asym_s8_s8_s8((int8_t *)tmp_buf,
                                                          src2,
                                                          dst_i32,
                                                          pOut,
                                                          out_scale,
                                                          out_shift,
                                                          col_counter,
                                                          in_tensor_ch,
                                                          out_tensor_ch,
                                                          out_offset,
                                                          act_min,
                                                          act_max,
                                                          contri_buf,
                                                          tiling_size);
            /* next in_tensor batch offset */
            in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
        }
    }
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64)
    if ((pad_x != 0) ||
        (pad_y != 0))
    {
        return -1;
    }

    (void)tmp_buf;

    // calculate the weight contribution
    int32_t contri_buf[out_tensor_ch];
    const int8_t *pWt = ker_weight;
    long vl;
    long maxvl_per_vg;
    NDS_VEC_VSETVLI(maxvl_per_vg, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

    if (bias != NULL)
    {
        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
        {
            long in_tensor_ch2 = in_tensor_ch;
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);     // init the acculators
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);                // const one for vd4dot

            while (in_tensor_ch2 >= maxvl_per_vg)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            //clean one of the dot product source
            long tmp_vl = in_tensor_ch2 + 3;
            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);

            while (in_tensor_ch2 > 0)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            const int32_t *pBias = &bias[cur_out_ch];
            NDS_VEC_VLE32_V(NDS_VEC_V8, pBias);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution back
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);    // add bias

            int32_t *pContri_buf = &contri_buf[cur_out_ch];
            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
        }
    }
    else
    {
        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
        {
            long in_tensor_ch2 = in_tensor_ch;
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
