            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);    // const one for vd4dot

            while (in_tensor_ch2 >= maxvl_per_vg)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            //clean one of the dot product source
            long tmp_vl = in_tensor_ch2 + 3;
            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);

            while (in_tensor_ch2 > 0)
            {
                NDS_VEC_VSETVLI(vl, in_tensor_ch2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                in_tensor_ch2 -= vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
