    uint32_t out_len  = (uint32_t) in_tensor_batch * out_tensor_ch * out_tensor_dim_x * out_tensor_dim_y;

    FILE *fptr_src1, *fptr_src2, *fptr_bias, *fptr_scale, *fptr_shift, *fptr_golden;
    //backup originally malloced starting address for later memory releasing
    void *src1_ori, *src2_ori, *out_ori, *in_tmp_buf_ori, *bias_ori, *output_shift_ori, *output_scale_ori, *golden_ori;

    int8_t *src1 = (int8_t*)test_malloc(sizeof(int8_t) * src1_len, "src1", &src1_ori);
    int8_t *src2 = (int8_t*)test_malloc(sizeof(int8_t) * src2_len, "src2", &src2_ori);
    int32_t *bias = NULL;
    if (!is_bias_null)
        bias = (int32_t*)test_malloc(sizeof(int32_t) * out_tensor_ch, "bias", &bias_ori);
    int32_t *output_shift = (int32_t*)test_malloc(sizeof(int32_t) * out_tensor_ch, "output_shift", &output_shift_ori);
    int32_t *output_scale = (int32_t*)test_malloc(sizeof(int32_t) * out_tensor_ch, "output_scale", &output_scale_ori);
    int8_t *output = (int8_t*)test_malloc(sizeof(int8_t) * out_len, "output", &out_ori);
    int8_t *golden = (int8_t*)test_malloc(sizeof(int8_t) * out_len, "golden", &golden_ori);
    int16_t *in_tmp_buf = (int16_t*)test_malloc(buf_len, "in_tmp_buf", &in_tmp_buf_ori);

    test_Fopen(fname_src1, "rb", &fptr_src1);
    test_Fopen(fname_src2, "rb", &fptr_src2);
